// Valida entrada e monta URL do snapshot. HTTP fica no nó seguinte para evitar timeout de 60s do Code task runner.
const PANEL_BASE = 'https://longflatworm-n8n.cloudfy.live/webhook';
const input = $json || {};
const code = String(input.cliente_codigo || '').trim();
const userId = String(input.user_id || '');
const url = PANEL_BASE + '/castor-panel-snapshot' + (userId ? '?userId=' + encodeURIComponent(userId) : '');
return [{ json: { user_id: userId, code, url, missing_code: !code } }];

const params = $('Prepare params').first().json;
if (params.missing_code) return [{ json: { ok: false, data: null, error: 'cliente_codigo obrigatorio' } }];
const resp = $json || {};
if (resp.error && !resp.ok) return [{ json: { ok: false, data: null, error: 'snapshot_failed: ' + (resp.error.message || resp.error) } }];
if (!resp || resp.ok === false) return [{ json: { ok: false, data: null, error: 'snapshot_failed: ' + ((resp && resp.error) || 'snapshot indisponivel') } }];
const snap = resp.data || {};
const cli = (snap.clientes || []).find(c => c.cliente_codigo === params.code);
if (!cli) return [{ json: { ok: false, code: params.code, data: null, error: 'cliente nao encontrado no snapshot' } }];
return [{ json: { ok: true, code: params.code, cliente: cli } }];

const meta = $('Snapshot fetch').first().json;
if (!meta.ok) return [{ json: meta }];
const visits = ($input.all() || []).map(i => i.json && (i.json.visit || i.json)).filter(Boolean);
const cli = meta.cliente;
return [{ json: { ok: true, data: { cliente: cli, visitas: visits, last_feedback: cli.last_feedback || null }, error: null } }];
